class TemperatureDashboardDelegate : public DrawableDashboardDelegate {
public:
    ~TemperatureDashboardDelegate() override = default;

    void dashboardDidOpen(BaseMenuRenderer* currentRenderer) override {
        const auto rend = reinterpret_cast<GraphicsDeviceRenderer*>(currentRenderer);
        const auto drawable = rend->getDeviceDrawable();
        drawable->setColors(WHITE, BLACK);
        drawable->drawXBitmap(Coord(14, 15), Coord(15,24), rawTempBits);
        drawable->drawXBitmap(Coord(48, 15), Coord(18, 24), rawHumidityBits);
        drawable->drawXBitmap(Coord(90, 15), Coord(24, 24), rawBarometricBits);
    }
};

TemperatureDashboardDelegate tempDashDelegate;
